// Loop over input items and add a new field called 'myNewField' to the JSON of each one
// This code handles responses where the model returned a JSON string inside content.parts[0].text
// It tries to parse directly, and if that fails it extracts the first {...} JSON substring and parses it.

const part = $json?.content?.parts?.[0]?.text ?? $json?.content?.parts?.[0] ?? null;

if (!part) {
  throw new Error('No text found in response node output at content.parts[0].text');
}

let parsed;
try {
  // try direct JSON parse (works when model returned raw JSON)
  parsed = JSON.parse(part);
} catch (err) {
  // fallback: extract the first {...} block and parse
  const match = part.match(/\{[\s\S]*\}/);
  if (!match) {
    throw new Error('Unable to find JSON object in model output');
  }
  try {
    parsed = JSON.parse(match[0]);
  } catch (err2) {
    throw new Error('Found JSON-like substring but failed to parse: ' + err2.message);
  }
}

// Ensure result has expected keys
parsed.subject = parsed.subject ?? '';
parsed.body = parsed.body ?? '';

// Return as single item so next nodes can use {{$node["Parse OpenAI"].json.subject}}
return [{ json: parsed }];

